def findCircleNum(isConnected):
    n = len(isConnected); vis = set(); provinces = 0
    def dfs(i):
        for j in range(n):
            if isConnected[i][j] and j not in vis:
                vis.add(j); dfs(j)
    for i in range(n):
        if i not in vis:
            vis.add(i); dfs(i); provinces += 1
    return provinces

